(function () {
  window.DENO_DOC_SEARCH_INDEX = {"kind":"search","nodes":[{"id":"namespace_bitmapfileheader","kind":[{"char":"I","kind":"Interface","title":"Interface"}],"name":"BitmapFileHeader","file":".","doc":"BITMAPFILEHEADER — the fixed 14-byte preamble of a BMP/DIB file.Always little-endian; the two-byte signature is \"BM\" for standard Windows bitmaps (other variants like \"BA\", \"CI\", \"CP\", \"IC\", \"PT\" are out of scope).","url":"././~/BitmapFileHeader.html","deprecated":false},{"id":"namespace_bitmapfileheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapFileHeader.signature","file":".","doc":"","url":"././~/BitmapFileHeader.signature.html","deprecated":false},{"id":"namespace_bitmapfileheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapFileHeader.fileSize","file":".","doc":"","url":"././~/BitmapFileHeader.fileSize.html","deprecated":false},{"id":"namespace_bitmapfileheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapFileHeader.reserved1","file":".","doc":"","url":"././~/BitmapFileHeader.reserved1.html","deprecated":false},{"id":"namespace_bitmapfileheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapFileHeader.reserved2","file":".","doc":"","url":"././~/BitmapFileHeader.reserved2.html","deprecated":false},{"id":"namespace_bitmapfileheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapFileHeader.pixelOffset","file":".","doc":"","url":"././~/BitmapFileHeader.pixelOffset.html","deprecated":false},{"id":"namespace_bitmapinfoheader","kind":[{"char":"I","kind":"Interface","title":"Interface"}],"name":"BitmapInfoHeader","file":".","doc":"BITMAPINFOHEADER — the 40-byte DIB header used by virtually all modern BMP files.The size field is what tells decoders which DIB header variant follows; for BITMAPINFOHEADER it is always 40. Larger variants (V4/V5) are not handled by this coder — read size first and dispatch externally if you need to support them.width is signed but in practice non-negative. height is signed: a negative value means the image is stored top-down (rows in natural reading order) instead of the BMP-default bottom-up. We deliberately preserve the sign rather than auto-flipping rows; row orientation is the caller's concern.","url":"././~/BitmapInfoHeader.html","deprecated":false},{"id":"namespace_bitmapinfoheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapInfoHeader.size","file":".","doc":"","url":"././~/BitmapInfoHeader.size.html","deprecated":false},{"id":"namespace_bitmapinfoheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapInfoHeader.width","file":".","doc":"","url":"././~/BitmapInfoHeader.width.html","deprecated":false},{"id":"namespace_bitmapinfoheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapInfoHeader.height","file":".","doc":"","url":"././~/BitmapInfoHeader.height.html","deprecated":false},{"id":"namespace_bitmapinfoheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapInfoHeader.planes","file":".","doc":"","url":"././~/BitmapInfoHeader.planes.html","deprecated":false},{"id":"namespace_bitmapinfoheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapInfoHeader.bpp","file":".","doc":"","url":"././~/BitmapInfoHeader.bpp.html","deprecated":false},{"id":"namespace_bitmapinfoheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapInfoHeader.compression","file":".","doc":"","url":"././~/BitmapInfoHeader.compression.html","deprecated":false},{"id":"namespace_bitmapinfoheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapInfoHeader.imageSize","file":".","doc":"","url":"././~/BitmapInfoHeader.imageSize.html","deprecated":false},{"id":"namespace_bitmapinfoheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapInfoHeader.xPixelsPerMeter","file":".","doc":"","url":"././~/BitmapInfoHeader.xPixelsPerMeter.html","deprecated":false},{"id":"namespace_bitmapinfoheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapInfoHeader.yPixelsPerMeter","file":".","doc":"","url":"././~/BitmapInfoHeader.yPixelsPerMeter.html","deprecated":false},{"id":"namespace_bitmapinfoheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapInfoHeader.colorsUsed","file":".","doc":"","url":"././~/BitmapInfoHeader.colorsUsed.html","deprecated":false},{"id":"namespace_bitmapinfoheader","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapInfoHeader.importantColors","file":".","doc":"","url":"././~/BitmapInfoHeader.importantColors.html","deprecated":false},{"id":"namespace_bitmapinfoheadercoder","kind":[{"char":"I","kind":"Interface","title":"Interface"}],"name":"BitmapInfoHeaderCoder","file":".","doc":"A BITMAPINFOHEADER coder bundled with the individual sub-coders for the three fields required to size pixel data.Holding on to the component coders lets you build ref()-driven pixel layouts: the file-level \"./mod.ts\".bmp coder uses widthCoder, heightCoder, and bppCoder to derive the buffer length.","url":"././~/BitmapInfoHeaderCoder.html","deprecated":false},{"id":"namespace_bitmapinfoheadercoder","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapInfoHeaderCoder.widthCoder","file":".","doc":"The signed 32-bit width field coder.","url":"././~/BitmapInfoHeaderCoder.widthCoder.html","deprecated":false},{"id":"namespace_bitmapinfoheadercoder","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapInfoHeaderCoder.heightCoder","file":".","doc":"The signed 32-bit height field coder (negative ⇒ top-down).","url":"././~/BitmapInfoHeaderCoder.heightCoder.html","deprecated":false},{"id":"namespace_bitmapinfoheadercoder","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BitmapInfoHeaderCoder.bppCoder","file":".","doc":"The unsigned 16-bit bpp field coder.","url":"././~/BitmapInfoHeaderCoder.bppCoder.html","deprecated":false},{"id":"namespace_bitmapfileheader","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"bitmapFileHeader","file":".","doc":"Creates a coder for the 14-byte BITMAPFILEHEADER.Field layout (little-endian throughout):signature   2 bytes — ASCII, \"BM\"fileSize    4 bytes — u32reserved1   2 bytes — u16reserved2   2 bytes — u16pixelOffset 4 bytes — u32","url":"././~/bitmapFileHeader.html","deprecated":false},{"id":"namespace_bitmapinfoheader","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"bitmapInfoHeader","file":".","doc":"Creates a coder for the 40-byte BITMAPINFOHEADER (the most common DIB header).All fields are little-endian. width and height are signed 32-bit; height being negative signals a top-down pixel layout.The returned coder also exposes its width, height, and bpp sub-coders so callers can build ref()-based pixel-data sizing without re-parsing the header.","url":"././~/bitmapInfoHeader.html","deprecated":false},{"id":"namespace_pixeldatasize","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"pixelDataSize","file":".","doc":"Computes the total pixel-data size for a BITMAPINFOHEADER, in bytes.The result is rowStride(width, bpp) * |height| — the absolute value of height is used so top-down (height < 0) and bottom-up images yield the same buffer size.","url":"././~/pixelDataSize.html","deprecated":false},{"id":"namespace_rowstride","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"rowStride","file":".","doc":"Computes the BMP row stride in bytes for a given pixel width and bit depth.BMP rows are padded so each row's byte length is a multiple of 4. The formula is the canonical floor((bpp * width + 31) / 32) * 4.","url":"././~/rowStride.html","deprecated":false},{"id":"namespace_bmpfile","kind":[{"char":"I","kind":"Interface","title":"Interface"}],"name":"BmpFile","file":".","doc":"Complete BMP file consisting of a BitmapFileHeader, a BitmapInfoHeader, and raw pixel data.No palette is modelled here; this shape targets the uncompressed 16/24/32-bpp common case.","url":"././~/BmpFile.html","deprecated":false},{"id":"namespace_bmpfile","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BmpFile.file","file":".","doc":"","url":"././~/BmpFile.file.html","deprecated":false},{"id":"namespace_bmpfile","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BmpFile.dib","file":".","doc":"","url":"././~/BmpFile.dib.html","deprecated":false},{"id":"namespace_bmpfile","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"BmpFile.pixelData","file":".","doc":"","url":"././~/BmpFile.pixelData.html","deprecated":false},{"id":"namespace_bmp","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"bmp","file":".","doc":"Creates a coder for a complete BMP file with a BITMAPINFOHEADER and no palette.The pixel-data length is derived from the DIB header's width, height, and bpp (see rowStride); the imageSize field is ignored, since BI_RGB encoders commonly leave it at zero.Use this for typical 16/24/32-bpp uncompressed images. For palette-indexed images or non-zero compression values, compose bitmapFileHeader, bitmapInfoHeader, and your own pixel/palette coders.","url":"././~/bmp.html","deprecated":false}]};
})()